Dynamic Inputs Pattern

The Problem
Inputs created by renderUI() don’t exist when reactives first evaluate:
output$dynamic_inputs &lt;- shiny::renderUI({
    # Creates input$item_1, input$item_2, etc.
    purrr::map(1:n, ~textInput(ns(paste0("item_", .x)), ...))
})

# This WON'T work - inputs don't exist yet
my_reactive &lt;- shiny::reactive({
    input$item_1  # NULL, and no dependency created
})


Solution: Polling (used in mod_palette and mod_legend)
shiny::observe({
    shiny::invalidateLater(500)  # Check every 500ms

    values &lt;- purrr::map(1:n, ~input[[paste0("item_", .x)]])

    if (!identical(values, stored_values())) {
        stored_values(values)
        trigger(trigger() + 1)  # For cache invalidation
    }
})
Characteristics: - 500ms polling interval (responsive enough, not wasteful) - Requires a trigger counter for bindCache() invalidation - Provides consistent “live” user experience across all dynamic inputs

Step 1: Prepare the Data
Reshape to long format and add summary row:

# Calculate averages
averages &lt;- data.frame(
  id = "ALL",
  accuracy = mean(warehouse_data$accuracy),
  error = mean(warehouse_data$error),
  null = mean(warehouse_data$null)
)

# Combine and reshape
dat_combined &lt;- warehouse_data |&gt;
  mutate(id = as.character(id)) |&gt;
  select(id, accuracy, error, null) |&gt;
  bind_rows(averages) |&gt;
  pivot_longer(
    cols = c(accuracy, null, error),
    names_to = "metric",
    values_to = "value"
  )

# Order by error rate and set factor levels
error_order &lt;- warehouse_data |&gt;
  arrange(error) |&gt;
  pull(id) |&gt;
  as.character()

dat_combined$id &lt;- factor(dat_combined$id, levels = c(error_order, "ALL"))
dat_combined$metric &lt;- factor(dat_combined$metric, levels = c("accuracy", "null", "error"))

# Add highlight color for high-error warehouses
high_error_ids &lt;- warehouse_data |&gt;
  filter(error &gt; 0.10) |&gt;
  pull(id) |&gt;
  as.character()

dat_combined &lt;- dat_combined |&gt;
  mutate(
    highlight = ifelse(id %in% high_error_ids & metric == "error", "highlight", "normal")
  )
